create table if not exists public.community_emojis (id uuid primary key default gen_random_uuid(), community_id uuid not null references public.communities(id) on delete cascade, name text not null check (name ~ '^[a-z0-9_]{1,32}$'), image_url text not null, created_by uuid not null references public.profiles(id) on delete restrict, created_at timestamptz not null default now(), deleted_at timestamptz, unique(community_id,name));
create table if not exists public.community_stickers (id uuid primary key default gen_random_uuid(), community_id uuid not null references public.communities(id) on delete cascade, name text not null check (name ~ '^[a-z0-9_]{1,32}$'), image_url text not null, created_by uuid not null references public.profiles(id) on delete restrict, created_at timestamptz not null default now(), deleted_at timestamptz, unique(community_id,name));
alter table public.community_emojis enable row level security;
alter table public.community_stickers enable row level security;
grant select,insert,update on public.community_emojis to authenticated;
grant select,insert,update on public.community_stickers to authenticated;
create policy "community_emojis_visible_select" on public.community_emojis for select to authenticated using (deleted_at is null and exists (select 1 from public.communities community where community.id=community_id and (community.visibility='public' or exists(select 1 from public.community_members member where member.community_id=community.id and member.user_id=auth.uid()))));
create policy "community_emojis_manager_insert" on public.community_emojis for insert to authenticated with check (created_by=auth.uid() and public.can_manage_channel_webhooks(community_id));
create policy "community_emojis_manager_delete" on public.community_emojis for update to authenticated using (public.can_manage_channel_webhooks(community_id)) with check (public.can_manage_channel_webhooks(community_id));
create policy "community_stickers_visible_select" on public.community_stickers for select to authenticated using (deleted_at is null and exists (select 1 from public.communities community where community.id=community_id and (community.visibility='public' or exists(select 1 from public.community_members member where member.community_id=community.id and member.user_id=auth.uid()))));
create policy "community_stickers_manager_insert" on public.community_stickers for insert to authenticated with check (created_by=auth.uid() and public.can_manage_channel_webhooks(community_id));
create policy "community_stickers_manager_delete" on public.community_stickers for update to authenticated using (public.can_manage_channel_webhooks(community_id)) with check (public.can_manage_channel_webhooks(community_id));
